module div_16bit(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output res_valid,
    output [15:0] result
);

    reg [15:0] SR;
    reg [7:0] NEG_DIVISOR;
    reg [3:0] cnt;
    reg start_cnt;
    reg [7:0] dividend_temp;
    reg [7:0] divisor_temp;
    reg sign_result;

    assign res_valid = (cnt == 4'b1000) ? 1'b1 : 1'b0;
    assign result = SR[15:0];

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            SR <= 16'b0;
            NEG_DIVISOR <= 8'b0;
            cnt <= 4'b0;
            start_cnt <= 1'b0;
            dividend_temp <= 8'b0;
            divisor_temp <= 8'b0;
            sign_result <= 1'b0;
        end else if (opn_valid) begin
            dividend_temp <= dividend;
            divisor_temp <= divisor;
            NEG_DIVISOR <= -divisor;
            SR <= {8'b0, dividend_temp};
            cnt <= 4'b1000;
            start_cnt <= 1'b1;
            sign_result <= sign & dividend[7];
        end else if (start_cnt) begin
            if (SR[15:8] >= divisor_temp) begin
                SR <= {SR[14:0], 1'b1};
                SR[15:8] <= SR[15:8] + NEG_DIVISOR;
            end else begin
                SR <= {SR[14:0], 1'b0};
            end
            cnt <= cnt - 1'b1;
            start_cnt <= 1'b0;
        end else if (res_ready) begin
            if (sign_result) begin
                SR[15:8] <= -SR[15:8];
            end
        end
    end

endmodule
